import Differentiators from './components/Differentiators';
import ContactForm from './components/ContactForm';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);
  const [currentPath, setCurrentPath] = useState(window.location.pathname);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };

    const handleLocationChange = () => {
      setCurrentPath(window.location.pathname);
      window.scrollTo(0, 0);
    };

    window.addEventListener('scroll', handleScroll);
    window.addEventListener('popstate', handleLocationChange);

    // Custom event for internal navigation
    window.addEventListener('navigate', handleLocationChange);

    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('popstate', handleLocationChange);
      window.removeEventListener('navigate', handleLocationChange);
    };
  }, []);

  // Utility to handle navigation without full page reload
  const navigate = (path: string) => {
    window.history.pushState({}, '', path);
    window.dispatchEvent(new Event('navigate'));
  };

  return (
    <div className="min-h-screen">
      <Header isScrolled={scrolled} onNavigate={navigate} />

      <main>
        {currentPath === '/collections' ? (
          <div className="pt-24 min-h-[60vh]">
            <section id="products">
              <ProductShowcase isPage={true} onNavigate={navigate} />
